@fragment fn fs_main(in: VertexOutput) -> @location(0) vec4<f32> {
  let radius = clamp(u.radius, 0.01, 0.5);
  let t = u.time * max(0.1, u.speed);
  let cy = 0.5 + sin(t) * clamp(u.intensity, 0.0, 0.5);
  let centerX = 0.5;

  let dx = in.uv.x - centerX;
  let dy = in.uv.y - cy;
  let hit = (abs(dx) <= radius) && (abs(dy) <= radius);

  let color = vec3<f32>(u.color_r, u.color_g, u.color_b);
  var outColor = vec3<f32>(0.0, 0.0, 0.0);
  if (hit) {
    outColor = color;
  }

  return vec4<f32>(outColor, 1.0);
}

